  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});

app.use(limiter);
```

---

### 5. No CORS Configuration (OWASP A05: Security Misconfiguration)

Without explicit CORS settings, the browser's same-origin policy applies by default — but this is fragile. If CORS middleware gets added later without a restrictive whitelist, the API is wide open.

**Recommendation:** Configure CORS explicitly:

```js
